The SV code attached below produces incorrect output for `out_reg_arg0` with `-DBUG`

with `-DBUG`: 
<img width="809" height="172" alt="Image" src="https://github.com/user-attachments/assets/88099126-2015-4ef5-b05c-2fd53d0911ab" />

without: 

<img width="789" height="179" alt="Image" src="https://github.com/user-attachments/assets/13d62a01-587e-40d2-aee5-8644e5c027e0" />

The bug occurs due to an array dereference *after* the new state has been written. Excerpt when lowering to ARC:
```
      %19 = arc.storage.get %arg0[4] : !arc.storage<9> -> !arc.state<!hw.array<1xi1>>
      %20 = arc.state_read %19 : <!hw.array<1xi1>>
      ...
      arc.state_write %19 = %23 : <!hw.array<1xi1>>
      %24 = hw.array_get %20[%c0_i0] : !hw.array<1xi1>, i0
```

I confirmed that manually swapping the `state_write` and `array_get` produces the expected behaviour. 

For a local workaround, I moved `array_get`s immediately after a `state_read` which fixed the problem in this case
```
   // Reorder hw.array_gets.
    SmallVector<hw::ArrayGetOp> arrayGets;
    getOperation().walk([&](hw::ArrayGetOp op) {
      arrayGets.push_back(op);
    });
    for (hw::ArrayGetOp op : arrayGets) {
      auto stateRead = op.getInput().getDefiningOp<StateReadOp>();
      if (!stateRead) continue;
      if (stateRead->getBlock() != op->getBlock()) continue;
      op->moveAfter(stateRead);
    }
```

Verilog repro:

```
module sm1(
  input        clk,
  input        rst,
  input        arg0_valid,
  output       result0_valid,
  output logic out_arg0,
  output logic out_reg_arg0
);
  wire tmp;

  first first (
    .clk           (clk),
    .rst           (rst),
    .result0       (tmp)
  );

  second second (
    .clk           (clk),
    .rst           (rst),
    .arg0          (tmp),
    .out_arg0      (out_arg0),
    .out_reg_arg0  (out_reg_arg0)
  );
endmodule

module first(
  input wire clk,
  input wire rst,
  output wire result0
);
`ifdef BUG
  reg __result0_reg[1];
  always_ff @ (posedge clk) begin
    if (rst) begin
      __result0_reg <= '{1'h0};
    end else begin
      __result0_reg <= '{1'b1};
    end
  end
  assign result0 = __result0_reg[0];
`else
  reg __result0_reg;
  always_ff @ (posedge clk) begin
    if (rst) begin
      __result0_reg <= 1'h0;
    end else begin
      __result0_reg <= 1'b1;
    end
  end
  assign result0 = __result0_reg;
`endif

endmodule

module second (
    input wire clk,
    input wire rst,
    input wire arg0,
    output wire out_arg0,
    output wire out_reg_arg0
);
  logic reg_arg0;
  always_ff @(posedge clk) begin
    if (rst) begin
      reg_arg0 <= 1'b0;
    end else begin
      reg_arg0 <= arg0;
    end
  end

  assign out_arg0 = arg0;
  assign out_reg_arg0 = reg_arg0;
endmodule
```

Incorrect IR
```
module {
  hw.module @sm1(in %clk : i1, in %rst : i1, in %arg0_valid : i1, out result0_valid : i1, out out_arg0 : i1, out out_reg_arg0 : i1) {
    %false = hw.constant false
    %first.result0 = hw.instance "first" @first(clk: %clk: i1, rst: %rst: i1) -> (result0: i1) {sv.namehint = "tmp"}
    %second.out_arg0, %second.out_reg_arg0 = hw.instance "second" @second(clk: %clk: i1, rst: %rst: i1, arg0: %first.result0: i1) -> (out_arg0: i1, out_reg_arg0: i1)
    hw.output %false, %second.out_arg0, %second.out_reg_arg0 : i1, i1, i1
  }
  hw.module private @first(in %clk : i1, in %rst : i1, out result0 : i1) {
    %0 = hw.aggregate_constant [true] : !hw.array<1xi1>
    %1 = hw.aggregate_constant [false] : !hw.array<1xi1>
    %c0_i0 = hw.constant 0 : i0
    %2 = comb.mux %rst, %1, %0 : !hw.array<1xi1>
    %3 = seq.to_clock %clk
    %__result0_reg = seq.firreg %2 clock %3 : !hw.array<1xi1>
    %4 = hw.array_get %__result0_reg[%c0_i0] : !hw.array<1xi1>, i0
    hw.output %4 : i1
  }
  hw.module private @second(in %clk : i1, in %rst : i1, in %arg0 : i1, out out_arg0 : i1, out out_reg_arg0 : i1) {
    %true = hw.constant true
    %0 = comb.xor %rst, %true : i1
    %1 = comb.and %0, %arg0 : i1
    %2 = seq.to_clock %clk
    %reg_arg0 = seq.firreg %1 clock %2 : i1
    hw.output %arg0, %reg_arg0 : i1, i1
  }
}
```

